@@ -121,6 +122,86 @@
 }

 /*
+ * find_parsetime --
+ *	Parse a string of the form [+-]([0-9][hmsYMWD])* and return the value.
+ */
+static time_t
+find_parsetime(plan, option, vp)
+	PLAN *plan;
+	char *option, *vp;
+{
+	time_t nsec, a;
+	char *s;
+
+	/* Determine comparison from leading + or -. */
+	s = vp;
+	switch (*s) {
+	case '+':
+		++s;
+		plan->flags = F_GREATER;
+		break;
+	case '-':
+		++s;
+		plan->flags = F_LESSTHAN;
+		break;
+	default:
+		plan->flags = F_EQUAL;
+		break;
+	}
+
+	if (!isdigit(*s))
+		errx(1, "%s: %s: illegal time value", option, vp);
+
+	plan->t_units = 0;
+	nsec = 0L;
+	a = 0L;
+	for (; *s; s++) {
+		if (isdigit(*s)) {
+			a = a*10L + *s-'0';
+		}
+		else if (*s == 's') {	/* seconds */
+			nsec += a;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'm') {	/* minutes */
+			nsec += a*60L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'h') {	/* hours */
+			nsec += a*3600L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'D') {	/* days */
+			nsec += a*86400L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'W') {	/* weeks */
+			nsec += a*604800L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'M') {	/* months (30D)*/
+			nsec += a*2592000L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else if (*s == 'Y') {	/* years (365D)*/
+			nsec += a*31536000L;
+			a = 0L;
+			plan->t_units = 1;
+		}
+		else {
+			errx(1, "%s: %s: bad unit", option, vp);
+		}
+	}
+	return nsec+a;
+}
+
+/*
  * The value of n for the inode times (atime, ctime, and mtime) is a range,
  * i.e. n matches from (n - 1) to n 24 hour periods.  This interacts with
  * -n, such that "-mtime -1" would be less than 0 days, which isn't what the
@@ -175,8 +256,13 @@
